mapper.select:
SELECT * FROM cers_university
WHERE 1=1

    AND (university_name LIKE CONCAT('%', #{keyword}, '%')
    OR location LIKE CONCAT('%', #{keyword}, '%')
    OR city LIKE CONCAT('%', #{keyword}, '%'))


    AND is_985 = #{is985}


    AND is_211 = #{is211}


    AND is_double_first = #{isDoubleFirst}


    AND type = #{type}


    AND level = #{level}

ORDER BY university_id ASC
